// Parse incoming Vapi server message
// Vapi sends different message types — we care about:
// - 'assistant-request' (initial setup)
// - 'tool-calls' (function calling)
// - 'end-of-call-report' (call summary)

const body = $input.item.json.body;
const messageType = body.message?.type || 'unknown';

// For conversation messages, extract the latest user transcript
let userMessage = '';
let callId = body.message?.call?.id || 'unknown';

if (messageType === 'tool-calls') {
  // Vapi is asking us to execute tool calls
  const toolCalls = body.message.toolCalls || [];
  return [{
    json: {
      type: 'tool-calls',
      call_id: callId,
      tool_calls: toolCalls,
      raw: body
    }
  }];
} else if (messageType === 'assistant-request') {
  // Initial call setup — respond with assistant config
  return [{
    json: {
      type: 'assistant-request',
      call_id: callId,
      raw: body
    }
  }];
} else if (messageType === 'conversation-update') {
  // Get the latest user message from the conversation
  const messages = body.message?.conversation || [];
  const lastUserMsg = messages.filter(m => m.role === 'user').pop();
  userMessage = lastUserMsg?.content || '';
  return [{
    json: {
      type: 'conversation-update',
      call_id: callId,
      user_message: userMessage,
      conversation: messages,
      raw: body
    }
  }];
} else if (messageType === 'end-of-call-report') {
  return [{
    json: {
      type: 'end-of-call-report',
      call_id: callId,
      summary: body.message?.summary || '',
      transcript: body.message?.transcript || '',
      duration_seconds: body.message?.durationSeconds || 0,
      raw: body
    }
  }];
}

// Unknown message type — pass through
return [{
  json: {
    type: messageType,
    call_id: callId,
    raw: body
  }
}];

// Process Vapi tool calls and return results
// This is where the AI receptionist logic lives for voice mode

const config = {
  "business": {
    "name": "Aroostook Family Dental",
    "phone": "(207) 555-0142",
    "address": "45 Main Street, Presque Isle, ME 04769",
    "website": "aroostookfamilydental.com"
  },
  "hours": {
    "monday": { "open": "08:00", "close": "17:00" },
    "tuesday": { "open": "08:00", "close": "17:00" },
    "wednesday": { "open": "08:00", "close": "17:00" },
    "thursday": { "open": "08:00", "close": "15:00" },
    "friday": { "open": "08:00", "close": "12:00" },
    "saturday": "closed",
    "sunday": "closed"
  },
  "services": [
    { "name": "Cleaning & Exam", "price": "$150-$250", "duration": "60 min" },
    { "name": "Filling", "price": "$175-$350", "duration": "45 min" },
    { "name": "Crown", "price": "$800-$1500", "duration": "90 min" },
    { "name": "Emergency Visit", "price": "Varies", "duration": "30 min" },
    { "name": "Whitening", "price": "$300-$500", "duration": "60 min" }
  ],
  "faq": {
    "insurance": "We accept most major dental insurance plans including Delta Dental, Cigna, Aetna, and MetLife.",
    "new_patients": "Yes, we're always welcoming new patients.",
    "payment_plans": "We offer CareCredit financing and in-house payment plans for procedures over $500.",
    "cancellation": "Please give us at least 24 hours notice to cancel or reschedule."
  }
};

const toolCalls = $json.tool_calls || [];
const results = [];

for (const call of toolCalls) {
  const funcName = call.function?.name;
  const args = typeof call.function?.arguments === 'string'
    ? JSON.parse(call.function.arguments)
    : call.function?.arguments || {};

  let result = '';

  switch (funcName) {
    case 'get_business_info':
      const query = (args.query || '').toLowerCase();
      if (query.includes('hour')) {
        result = JSON.stringify(config.hours);
      } else if (query.includes('service') || query.includes('pricing') || query.includes('price')) {
        result = JSON.stringify(config.services);
      } else if (query.includes('insurance')) {
        result = config.faq.insurance;
      } else if (query.includes('location') || query.includes('address')) {
        result = `We're located at ${config.business.address}`;
      } else if (query.includes('new patient')) {
        result = config.faq.new_patients;
      } else if (query.includes('payment') || query.includes('financing')) {
        result = config.faq.payment_plans;
      } else {
        result = JSON.stringify(config.business);
      }
      break;

    case 'check_availability':
      // In production, this queries Google Calendar
      // For now, return a simulated response
      result = JSON.stringify({
        available: true,
        date: args.date,
        time: args.time,
        appointment_type: args.appointment_type,
        note: 'Connect Google Calendar API for real availability'
      });
      break;

    case 'book_appointment':
      // In production, this creates a Google Calendar event
      result = JSON.stringify({
        booked: true,
        patient_name: args.patient_name,
        date: args.date,
        time: args.time,
        appointment_type: args.appointment_type,
        confirmation: `Appointment booked for ${args.patient_name} on ${args.date} at ${args.time}`,
        note: 'Connect Google Calendar API for real booking'
      });
      break;

    case 'take_message':
      result = JSON.stringify({
        taken: true,
        message: `Message from ${args.caller_name} (${args.caller_phone}): ${args.message}`,
        urgency: args.urgency
      });
      break;

    case 'transfer_to_human':
      result = JSON.stringify({
        transferred: true,
        reason: args.reason,
        message: 'A staff member will follow up shortly.'
      });
      break;

    default:
      result = JSON.stringify({ error: `Unknown function: ${funcName}` });
  }

  results.push({
    toolCallId: call.id,
    result: result
  });
}

// Return in Vapi's expected format
return [{
  json: {
    results: results
  }
}];
